import java.util.Scanner;

public class BufferOverflowExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        int bufferSize = 10;
        char[] buffer = new char[bufferSize]; // Buffer of fixed size 10

        // Copy user input into buffer with proper length check
        int length = Math.min(input.length(), bufferSize); // Limit input length to buffer size
        input.getChars(0, length, buffer, 0);

        System.out.println("Buffer overflow avoided!");
    }
}

### Explanation:
취약유형: Buffer Overflow
